1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	const cellOf = (key: string): Cell => {
11	  const [x, y] = key.split(",");
12	  return [Number(x), Number(y)];
13	};
14	
15	const survives = (isAlive: boolean, neighbors: number): boolean =>
16	  neighbors === 3 || (isAlive && neighbors === 2);
17	
18	const countNeighbors = (cells: Cell[]): Map<string, number> => {
19	  const counts = new Map<string, number>();
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const key = keyOf([x + dx, y + dy]);
23	      counts.set(key, (counts.get(key) ?? 0) + 1);
24	    }
25	  }
26	  return counts;
27	};
28	
29	export function nextGeneration(cells: Cell[]): Cell[] {
30	  const alive = new Set(cells.map(keyOf));
31	  const result: Cell[] = [];
32	  for (const [key, count] of countNeighbors(cells)) {
33	    if (survives(alive.has(key), count)) result.push(cellOf(key));
34	  }
35	  return result;
36	}
37

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a block (still life) unchanged", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a blinker from vertical to horizontal", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should bring a dead cell to life with exactly 3 live neighbors (reproduction)", () => {
26	    // L-shape: three live cells, dead cell (1,1) has 3 live neighbors
27	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
28	    const result = nextGeneration(input);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
32	    // Center (1,1) has 4 live neighbors: corners (0,0),(2,0),(0,2),(2,2)
33	    const input: [number, number][] = [[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]];
34	    const result = nextGeneration(input);
35	    expect(result).not.toContainEqual([1, 1]);
36	  });
37	  it.todo("should handle negative coordinates");
38	});
